import aside from '@/components/shared/aside/aside';
import nav from '@/components/shared/nav/nav';
import { ComponentModule, render } from '@/main';
import { TOAST_TRIGGER } from '@/models/events';
import { ToastError, ToastSuccess } from '@/models/toast';
import { url } from '@/services/api.service';
import { getAuthenticatedUser } from '@/services/auth.service';

export default {
    name: () => 'presaleNew',
    template: () => import('./presale-new.html?raw'),
    data: () => ({
        user: getAuthenticatedUser(),
        nav: null as string | null,
        aside: null as string | null,
        loading: true,

        presaleCif: '',

        submitting: false,

        async init() {
            console.log('presale-new@init');

            this.nav = await render(nav);
            this.aside = await render(aside);

            this.loading = false;
        },

        async createPresale() {
            this.submitting = true;
            try {
                const r = await fetch(url('isiWeb/web/v1/empresas/01/presuntos'), {
                    credentials: 'include',
                    method: 'POST',
                    headers: {
                        'Content-Type': 'application/json',
                    },
                    body: JSON.stringify({
                        cif: this.presaleCif,
                    }),
                });
                if (!r.ok) {
                    const response = await r.json();
                    throw new Error(response.message);
                }

                const response = await r.json();
                if (response) this.$dispatch(TOAST_TRIGGER, { msg: response.message, level: ToastSuccess });
                this.$router.navigate(`/presunto/modify/${response.data.pre}`);
            } catch (error) {
                console.error(error);
                this.$dispatch(TOAST_TRIGGER, { msg: error, level: ToastError });
            }
            this.submitting = false;
        },
    }),
} as ComponentModule;
